import React, { useState, useEffect, useRef } from 'react';
import { StyleSheet, Text, View, TextInput, TouchableOpacity, ScrollView, Animated, Easing, SafeAreaView, KeyboardAvoidingView, Platform, Alert, Image } from 'react-native';
import { StatusBar } from 'expo-status-bar';

export default function App() {
  const [view, setView] = useState('rip'); // 'rip' | 'saved' | 'detail'
  const [saved, setSaved] = useState([]);
  const [url, setUrl] = useState('');
  const [loading, setLoading] = useState(false);
  const [recipe, setRecipe] = useState(null);
  const [loadingUrl, setLoadingUrl] = useState('');

  const ripple = () => {
    if (!url || !url.startsWith('http')) {
      Alert.alert('Enter a full URL', 'Make sure it starts with https://');
      return;
    }
    setLoading(true);
    setLoadingUrl(url);
    setRecipe(null);
    setView('detail');
  };

  // Simulate extraction for demo
  useEffect(() => {
    if (loadingUrl && view === 'detail') {
      setTimeout(() => {
        setLoading(false);
        setRecipe({
          _id: Date.now().toString(),
          title: 'Loaded: ' + loadingUrl.replace('https://','').replace('http://','').split('/')[0],
          author: 'Recipe Rip',
          ingredients: [
            '2 cups all-purpose flour',
            '1 teaspoon baking powder',
            '1/2 teaspoon salt',
            '1 cup milk',
            '2 large eggs',
            '2 tablespoons butter, melted',
          ],
          instructions: [
            'Mix flour, baking powder, and salt in a large bowl.',
            'In another bowl, whisk together milk, eggs, and melted butter.',
            'Pour wet ingredients into dry ingredients and stir until just combined.',
            'Heat a griddle or pan over medium heat and lightly butter.',
            'Pour 1/4 cup batter per pancake and cook until bubbles form.',
            'Flip and cook until golden brown on the other side.',
            'Serve warm with maple syrup.',
          ],
          sourceUrl: loadingUrl,
        });
      }, 2500);
    }
  }, [loadingUrl]);

  const toggleSave = () => {
    if (!recipe) return;
    const idx = saved.findIndex(r => r._id === recipe._id);
    if (idx >= 0) {
      const newSaved = [...saved];
      newSaved.splice(idx, 1);
      setSaved(newSaved);
    } else {
      setSaved([...saved, { ...recipe, _saved: true }]);
    }
  };

  const showDetail = (r) => {
    setRecipe(r);
    setView('detail');
  };

  const deleteSaved = (id) => {
    setSaved(saved.filter(r => r._id !== id));
  };

  const isSaved = recipe ? saved.some(r => r._id === recipe._id) : false;

  return (
    <SafeAreaView style={styles.container}>
      <StatusBar style="dark" />

      {/* Header */}
      <View style={styles.header}>
        <View style={styles.logo}>
          <Text style={styles.logoIconText}>🍴</Text>
          <Text style={styles.logoTitle}>Recipe Rip</Text>
        </View>
      </View>

      {/* Content Area */}
      <View style={styles.content}>
        {/* Loading Screen */}
        {view === 'detail' && loading && (
          <View style={styles.loadingWrapper}>
            <View style={styles.loadingPanel}>
              <View style={styles.loadingSpinner} />
              <Text style={styles.loadingText}>Extracting recipe...</Text>
              <Text style={styles.loadingUrlText}>
                {loadingUrl.replace('https://','').replace('http://','').split('/')[0]}
              </Text>
            </View>
          </View>
        )}

        {/* Detail View */}
        {view === 'detail' && !loading && recipe && (
          <ScrollView style={styles.detailScroll}>
            <TouchableOpacity style={styles.backBtn} onPress={() => { setView('rip'); setRecipe(null); setLoadingUrl(''); }}>
              <Text style={styles.backBtnText}>← Back</Text>
            </TouchableOpacity>

            <Text style={styles.recipeTitle}>{recipe.title}</Text>
            {recipe.author && <Text style={styles.recipeAuthor}>by {recipe.author}</Text>}

            <TouchableOpacity style={styles.saveBtn} onPress={toggleSave}>
              <Text style={styles.saveBtnText}>{isSaved ? '✓ Saved' : '+ Save Recipe'}</Text>
            </TouchableOpacity>

            {recipe.ingredients && recipe.ingredients.length > 0 && (
              <>
                <Text style={styles.sectionTitle}>Ingredients ({recipe.ingredients.length})</Text>
                {recipe.ingredients.map((ing, i) => (
                  <View key={i} style={styles.ingredientRow}>
                    <Text style={styles.ingredientBullet}>•</Text>
                    <Text style={styles.ingredientText}>{ing}</Text>
                  </View>
                ))}
              </>
            )}

            {recipe.instructions && recipe.instructions.length > 0 && (
              <>
                <Text style={styles.sectionTitle}>Instructions ({recipe.instructions.length} steps)</Text>
                {recipe.instructions.map((step, i) => (
                  <View key={i} style={styles.stepRow}>
                    <View style={styles.stepNumber}>
                      <Text style={styles.stepNumberText}>{i + 1}</Text>
                    </View>
                    <Text style={styles.stepText}>{step}</Text>
                  </View>
                ))}
              </>
            )}

            {recipe.sourceUrl && (
              <TouchableOpacity style={styles.originBtn}>
                <Text style={styles.originBtnText}>↗ Open Original Recipe</Text>
              </TouchableOpacity>
            )}

            <View style={styles.bottomSpacer} />
          </ScrollView>
        )}

        {/* Rip View - Empty State */}
        {view === 'rip' && (
          <View style={styles.emptyState}>
            <Text style={styles.emptyEmoji}>Stop reading. Start cooking.</Text>
            <Text style={styles.emptyDesc}>Paste any recipe URL above to get just the recipe. No ads, no life story.</Text>
          </View>
        )}

        {/* Saved View */}
        {view === 'saved' && (
          <View style={styles.savedView}>
            {saved.length === 0 ? (
              <View style={styles.emptyState}>
                <Text style={styles.emptyEmoji}>No saved recipes yet</Text>
                <Text style={styles.emptyDesc}>Rip a recipe and tap "Save Recipe" to keep it here.</Text>
              </View>
            ) : (
              <ScrollView style={styles.savedList}>
                {saved.map(r => (
                  <TouchableOpacity key={r._id} style={styles.recipeCard} onPress={() => showDetail(r)}>
                    <View style={styles.cardThumb}>
                      <Text style={styles.cardThumbEmoji}>R</Text>
                    </View>
                    <View style={styles.cardInfo}>
                      <Text style={styles.cardTitle}>{r.title}</Text>
                      <Text style={styles.cardMeta}>{(r.ingredients || []).length} ingredients</Text>
                    </View>
                    <TouchableOpacity style={styles.deleteBtn} onPress={() => deleteSaved(r._id)}>
                      <Text style={styles.deleteBtnText}>X</Text>
                    </TouchableOpacity>
                  </TouchableOpacity>
                ))}
              </ScrollView>
            )}
          </View>
        )}
      </View>

      {/* Bottom Tabs - Fixed at bottom */}
      <View style={styles.bottomTabs}>
        <TouchableOpacity 
          style={[styles.tab, view === 'rip' && styles.tabActive]}
          onPress={() => setView('rip')}
        >
          <Text style={[styles.tabText, view === 'rip' && styles.tabTextActive]}>Rip</Text>
        </TouchableOpacity>
        <TouchableOpacity 
          style={[styles.tab, view === 'saved' && styles.tabActive]}
          onPress={() => setView('saved')}
        >
          <Text style={[styles.tabText, view === 'saved' && styles.tabTextActive]}>
            Saved {saved.length > 0 && <Text style={styles.tabBadge}>{saved.length}</Text>}
          </Text>
        </TouchableOpacity>
      </View>

      {/* Input Bar - Fixed at bottom */}
      <View style={styles.inputBar}>
        <TextInput
          style={styles.input}
          placeholder="https://www.seriouseats.com/recipe..."
          value={url}
          onChangeText={setUrl}
          autoCapitalize="none"
          autoCorrect={false}
          keyboardType="url"
        />
        <TouchableOpacity style={styles.ripBtn} onPress={ripple}>
          <Text style={styles.ripBtnText}>Rip It</Text>
        </TouchableOpacity>
      </View>
    </SafeAreaView>
  );
}

